update chat_tbl
set is_read = TRUE
where receiver_id = #{memberId}
  and sender_id = #{partnerId}
  and is_read = FALSE
  and deleted_yn = FALSE

update chat_tbl
set sender_hidden_at = NOW()
where sender_id = #{memberId}
  and receiver_id = #{partnerId}

update chat_tbl
set receiver_hidden_at = NOW()
where sender_id = #{partnerId}
  and receiver_id = #{memberId}
